const data = $input.item.json;

// suporta { reports: [...] } ou array direto
const reports = Array.isArray(data) ? data : (data.reports || data.data || data.bots || []);
const summary = data.summary || data;

const top5 = reports.slice(0, 5);
const dateStr = new Date().toLocaleDateString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  weekday: 'long', day: '2-digit', month: '2-digit'
});

const lines = top5.length > 0
  ? top5.map((r, i) => {
      const name = r.bot_name || r.name || r.specialist || `Bot ${i+1}`;
      const tasks = r.tasks_done ?? r.tasks ?? r.total ?? 0;
      const tokens = r.tokens_used ?? r.tokens ?? 0;
      const status = r.status === 'error' ? '🔴' : '🟢';
      return `  ${i+1}. ${status} *${name}*: ${tasks} tarefas · ${tokens} tokens`;
    }).join('\n')
  : '  • Sem dados hoje';

const totalTasks = summary.total_tasks ?? reports.reduce((a, r) => a + (r.tasks_done || r.tasks || 0), 0);
const totalErrors = summary.errors ?? reports.filter(r => r.status === 'error').length;

const message = [
  `📊 *Relatório Titanio — ${dateStr}*`,
  '',
  `✅ Tarefas concluídas: *${totalTasks}*`,
  `❌ Erros: *${totalErrors}*`,
  '',
  '*Top 5 especialistas:*',
  lines,
  '',
  `_${new Date().toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo' })} · Titanio Dashboard_`
].join('\n');

return [{ json: { message } }];
